- <!-- Forge AI Workspace entry page -->
- <!DOCTYPE html>
- <!-- Main web app shell. -->
- <html lang="en">
- <head>
-   <meta charset="UTF-8" />
-   <meta name="viewport" content="width=device-width, initial-scale=1.0" />
-   <title>Forge AI Workspace</title>
-   <style>
-     * {
-       box-sizing: border-box;
-     }
- 
-     body {
-       margin: 0;
-       font-family: Arial, sans-serif;
-       background: #0f172a;
-       color: #e2e8f0;
-     }
- 
-     .app {
-       max-width: 1100px;
-       margin: 0 auto;
-       padding: 24px;
-     }
- 
-     .header {
-       margin-bottom: 24px;
-     }
- 
-     .test-banner {
-       margin-bottom: 18px;
-       border: 1px solid #facc15;
-       border-radius: 8px;
-       background: #422006;
-       color: #fef3c7;
-       padding: 12px 14px;
-       font-weight: 700;
-     }
- 
-     .header h1 {
-       margin: 0 0 8px;
-       font-size: 28px;
-     }
- 
-     .header p {
-       margin: 0;
-       color: #94a3b8;
-       line-height: 1.6;
-     }
- 
-     .grid {
-       display: grid;
-       grid-template-columns: 1.2fr 1fr;
-       gap: 20px;
-     }
- 
-     .panel {
-       background: #111827;
-       border: 1px solid #1f2937;
-       border-radius: 16px;
-       padding: 20px;
-     }
- 
-     .panel h2 {
-       margin-top: 0;
-       margin-bottom: 16px;
-       font-size: 20px;
-     }
- 
-     label {
-       display: block;
-       margin-bottom: 8px;
-       font-size: 14px;
-       color: #cbd5e1;
-     }
- 
-     textarea,
-     select {
-       width: 100%;
-       border-radius: 12px;
-       border: 1px solid #334155;
-       background: #0b1220;
-       color: #e2e8f0;
-       padding: 14px;
-       font-size: 15px;
-       line-height: 1.6;
-       outline: none;
-     }
- 
-     textarea {
-       min-height: 260px;
-       resize: vertical;
-     }
- 
-     textarea:focus,
-     select:focus {
-       border-color: #38bdf8;
-     }
- 
-     .actions {
-       display: flex;
-       gap: 12px;
-       margin-top: 16px;
-       flex-wrap: wrap;
-     }
- 
-     button {
-       border: 0;
-       border-radius: 12px;
-       padding: 12px 18px;
-       font-size: 14px;
-       font-weight: 700;
-       cursor: pointer;
-     }
- 
-     .primary {
-       background: #38bdf8;
-       color: #082f49;
-     }
- 
-     .secondary {
-       background: #1e293b;
-       color: #e2e8f0;
-       border: 1px solid #334155;
-     }
- 
-     .danger {
-       background: #3f1d1d;
-       color: #fecaca;
-       border: 1px solid #7f1d1d;
-     }
- 
-     button:disabled {
-       opacity: 0.5;
-       cursor: not-allowed;
-     }
- 
-     .status {
-       margin-top: 14px;
-       padding: 12px 14px;
-       border-radius: 12px;
-       background: #0b1220;
-       border: 1px solid #1e293b;
-       color: #cbd5e1;
-       min-height: 46px;
-       white-space: pre-wrap;
-     }
- 
-     .section {
-       margin-top: 18px;
-     }
- 
-     .output-box {
-       background: #0b1220;
-       border: 1px solid #1e293b;
-       border-radius: 12px;
-       padding: 14px;
-       min-height: 180px;
-       white-space: pre-wrap;
-       overflow: auto;
-       line-height: 1.6;
-     }
- 
-     .file-list {
-       display: flex;
-       flex-direction: column;
-       gap: 12px;
-     }
- 
-     .file-card {
-       background: #0b1220;
-       border: 1px solid #1e293b;
-       border-radius: 12px;
-       padding: 14px;
-     }
- 
-     .file-path {
-       font-weight: 700;
-       margin-bottom: 8px;
-       color: #7dd3fc;
-       word-break: break-word;
-     }
- 
-     .file-preview {
-       color: #cbd5e1;
-       white-space: pre-wrap;
-       word-break: break-word;
-       max-height: 180px;
-       overflow: auto;
-       line-height: 1.6;
-     }
- 
-     .empty {
-       color: #94a3b8;
-     }
- 
-     .workspace-shell {
-       display: grid;
-       grid-template-columns: minmax(0, 1.45fr) minmax(300px, 0.8fr);
-       gap: 20px;
-       align-items: start;
-     }
- 
-     .chat-panel {
-       background: #111827;
-       border: 1px solid #1f2937;
-       border-radius: 20px;
-       padding: 20px;
-     }
- 
-     .chat-stream {
-       display: flex;
-       flex-direction: column;
-       gap: 16px;
-     }
- 
-     .chat-message {
-       border: 1px solid #1e293b;
-       border-radius: 18px;
-       padding: 16px;
-       background: #0b1220;
-     }
- 
-     .chat-message.user {
-       background: #082f49;
-       border-color: #0ea5e9;
-     }
- 
-     .chat-message.assistant {
-       background: #111827;
-     }
- 
-     .message-label {
-       font-size: 12px;
-       text-transform: uppercase;
-       letter-spacing: 0.08em;
-       color: #94a3b8;
-       margin-bottom: 10px;
-       font-weight: 700;
-     }
- 
-     .message-title {
-       margin: 0 0 12px;
-       font-size: 18px;
-     }
- 
-     .composer-box {
-       display: flex;
-       flex-direction: column;
-       gap: 12px;
-     }
- 
-     .composer-box textarea {
-       min-height: 170px;
-     }
- 
-     .message-actions {
-       display: flex;
-       gap: 12px;
-       flex-wrap: wrap;
-       align-items: center;
-     }
- 
-     .inline-status {
-       margin-top: 0;
-       min-height: auto;
-       flex: 1;
-     }
- 
-     .assistant-stack {
-       display: flex;
-       flex-direction: column;
-       gap: 12px;
-     }
- 
-     .workspace-sidebar {
-       display: flex;
-       flex-direction: column;
-       gap: 16px;
-     }
- 
-     .sidebar-card {
-       background: #111827;
-       border: 1px solid #1f2937;
-       border-radius: 18px;
-       padding: 18px;
-     }
- 
-     .sidebar-card h2 {
-       margin: 0 0 14px;
-       font-size: 18px;
-     }
- 
-     .compact-box {
-       min-height: 120px;
-     }
- 
-     .auth-fields {
-       display: flex;
-       flex-direction: column;
-       gap: 10px;
-     }
- 
-     .auth-fields textarea {
-       min-height: 60px;
-     }
- 
-     .approval-actions {
-       margin-top: 14px;
-     }
- 
-     .hidden-state {
-       display: none;
-     }
- 
-     .strategy-choice-list {
-       display: flex;
-       flex-direction: column;
-       gap: 10px;
-     }
- 
-     .strategy-choice-btn {
-       width: 100%;
-       text-align: left;
-       background: #0b1220;
-       color: #e2e8f0;
-       border: 1px solid #334155;
-       border-radius: 12px;
-       padding: 12px 14px;
-       cursor: pointer;
-       font-size: 14px;
-       line-height: 1.6;
-     }
- 
-     .strategy-choice-btn:hover {
-       border-color: #38bdf8;
-       background: #0f172a;
-     }
- 
-     .strategy-choice-btn strong {
-       display: block;
-       color: #7dd3fc;
-       margin-bottom: 6px;
-     }
- 
-     .footer {
-       margin-top: 24px;
-       padding-top: 18px;
-       border-top: 1px solid #1f2937;
-       color: #94a3b8;
-       font-size: 14px;
-       text-align: center;
-     }
- 
-     .footer p {
-       margin: 0;
-     }
- 
-     @media (max-width: 900px) {
-       .workspace-shell {
-         grid-template-columns: 1fr;
-       }
-     }
- 
-     @media (max-width: 900px) {
-       .grid {
-         grid-template-columns: 1fr;
-       }
-     }
-   </style>
- </head>
- <body>
-   <div class="app">
-     <div class="test-banner">Test banner</div>
- 
-     <div class="header">
-       <h1>Forge AI Workspace</h1>
-       <p>اكتب طلبك بالعربي أو بالإنجليزي. النظام هيجهز Draft للملفات المقترحة، وبعد مراجعتك وموافقتك يتم إنشاء Decision Packet governed بدل الكتابة المباشرة.</p>
-     </div>
- 
-     <div class="workspace-shell">
-       <div class="chat-panel">
-         <div class="chat-stream">
-           <div class="chat-message user">
-             <div class="message-label">You</div>
-             <h2 class="message-title">Start a conversation</h2>
- 
-             <div class="composer-box">
-               <label for="requestInput">Your request</label>
-               <label for="projectSelect">Active project</label>
-               <select id="projectSelect"></select>
- 
-               <div id="projectStateBox" class="status">Loading project state...</div>
- 
-               <textarea id="requestInput" placeholder="اكتب طلبك هنا...&#10;&#10;مثال: أنشئ ملف نصي يحتوي خطة عملية لبناء أول MVP لمشروع تقليل الهدر في المصانع الصغيرة في مصر."></textarea>
- 
-               <div class="message-actions">
-                 <button id="chatSendBtn" class="primary">Send</button>
-                 <div id="statusBox" class="status inline-status">Ready.</div>
-               </div>
-             </div>
-           </div>
- 
-           <div class="hidden-state" aria-hidden="true">
-             <div id="responseBox" class="output-box empty">No response yet.</div>
- 
-             <div id="filesBox" class="file-list">
-               <div class="file-card empty">No files proposed yet.</div>
-             </div>
- 
-             <div id="previewBox" class="file-list">
-               <div class="file-card empty">No diff preview yet.</div>
-             </div>
- 
-             <div id="analysisBox" class="output-box empty">No operation analysis yet.</div>
-           </div>
- 
-           <div class="chat-message assistant">
-             <div class="message-label">Approval</div>
-             <h2 class="message-title">Decision</h2>
- 
-             <label for="approverRoleSelect">Approver role</label>
-             <select id="approverRoleSelect">
-               <option value="cto">cto</option>
-             </select>
- 
-             <div class="assistant-stack">
-               <div id="approvalInfoBox" class="output-box compact-box empty">Approval policy not loaded yet.</div>
-               <div id="operationInfoBox" class="output-box compact-box empty">Operation summary not loaded yet.</div>
-             </div>
- 
-             <div class="actions approval-actions">
-               <button id="approveBtn" class="primary" disabled>Approve & Queue Decision</button>
-               <button id="rejectBtn" class="danger" disabled>Reject</button>
-             </div>
-           </div>
-         </div>
-       </div>
- 
-       <div class="workspace-sidebar">
-         <div class="sidebar-card">
-           <h2>Project Activity</h2>
-           <div id="historyBox" class="file-list">
-             <div class="file-card empty">No write history yet.</div>
-           </div>
-         </div>
- 
-         <div class="sidebar-card">
-           <h2>Conversation Memory</h2>
-           <div id="conversationHistoryBox" class="file-list">
-             <div class="file-card empty">No conversation turns yet.</div>
-           </div>
-         </div>
- 
-         <div class="sidebar-card">
-           <h2>Workspace Access</h2>
- 
-           <div class="auth-fields">
-             <label for="authUsernameInput">Username</label>
-             <textarea id="authUsernameInput">test</textarea>
- 
-             <label for="authPasswordInput">Password</label>
-             <textarea id="authPasswordInput">1234</textarea>
-           </div>
- 
-           <div class="actions">
-             <button id="authRegisterBtn" class="secondary">Register</button>
-             <button id="authLoginBtn" class="secondary">Login</button>
-           </div>
- 
-           <div id="authResultBox" class="output-box compact-box empty">No auth response yet.</div>
-         </div>
-       </div>
-     </div>
- 
-     <footer class="footer">
-       <p>&copy; 2026 Forge AI Workspace. All rights reserved.</p>
-     </footer>
-   </div>
- 
-   <script>
-     const requestInput = document.getElementById("requestInput");
-     const projectSelect = document.getElementById("projectSelect");
-     const projectStateBox = document.getElementById("projectStateBox");
-     const chatSendBtn = document.getElementById("chatSendBtn");
-     const approveBtn = document.getElementById("approveBtn");
-     const rejectBtn = document.getElementById("rejectBtn");
-     const approverRoleSelect = document.getElementById("approverRoleSelect");
-     const statusBox = document.getElementById("statusBox");
-     const responseBox = document.getElementById("responseBox");
-     const filesBox = document.getElementById("filesBox");
-     const historyBox = document.getElementById("historyBox");
-     const conversationHistoryBox = document.getElementById("conversationHistoryBox");
-     const previewBox = document.getElementById("previewBox");
-     const analysisBox = document.getElementById("analysisBox");
-     const approvalInfoBox = document.getElementById("approvalInfoBox");
-     const operationInfoBox = document.getElementById("operationInfoBox");
- 
-     const authUsernameInput = document.getElementById("authUsernameInput");
-     const authPasswordInput = document.getElementById("authPasswordInput");
-     const authRegisterBtn = document.getElementById("authRegisterBtn");
-     const authLoginBtn = document.getElementById("authLoginBtn");
-     const authResultBox = document.getElementById("authResultBox");
- 
-     const chatStream = document.querySelector(".chat-stream");
- 
-     function appendMessage(type, title, contentHtml) {
-       const wrapper = document.createElement("div");
-       wrapper.className = "chat-message " + (type === "user" ? "user" : "assistant");
- 
-       wrapper.innerHTML = `
-         <div class="message-label">${type === "user" ? "You" : "AI Workspace"}</div>
-         <h2 class="message-title">${title}</h2>
-         <div>${contentHtml}</div>
-       `;
- 
-       chatStream.appendChild(wrapper);
-       wrapper.scrollIntoView({ behavior: "smooth", block: "end" });
-     }
- 
-     function escapeHtml(value) {
-       return String(value || "")
-         .replace(/&/g, "&amp;")
-         .replace(/</g, "&lt;")
-         .replace(/>/g, "&gt;")
-         .replace(/"/g, "&quot;")
-         .replace(/'/g, "&#39;");
-     }
- 
-     function formatMessageText(value) {
-       return escapeHtml(value).replace(/\n/g, "<br>");
-     }
- 
-     function pushMessage(type, title, contentHtml) {
-       activeTurn.messages.push({
-         type,
-         title,
-         content: contentHtml
-       });
- 
-       appendMessage(type, title, contentHtml);
-     }
- 
-     function buildStrategyChoiceHtml(items) {
-       const list = Array.isArray(items) ? items : [];
- 
-       if (list.length === 0) {
-         return `<div class="file-preview">${formatMessageText("No strategies available.")}</div>`;
-       }
- 
-       return `
-         <div class="strategy-choice-list">
-           ${list.map((item, index) => `
-             <button
-               type="button"
-               class="strategy-choice-btn"
-               data-strategy-choice="${index + 1}"
-             >
-               <strong>${index + 1}. ${escapeHtml(item.title || "Untitled strategy")} [${escapeHtml(item.strategy_id || "UNKNOWN")}]</strong>
-               <div>Target: ${escapeHtml(item.target_file || "")}</div>
-               <div>Score: ${escapeHtml(item.score ?? "")}</div>
-               <div>Why: ${escapeHtml(item.rationale || "")}</div>
-             </button>
-           `).join("")}
-         </div>
-       `;
-     }
- 
-     function createEmptyTurnState() {
-       return {
-         draft: null,
-         request: "",
-         projectId: "default_project",
-         proposalId: "",
-         preview: [],
-         requiredRoles: [],
-         approvalPolicyVersion: "",
-         operationMode: "",
-         fileCount: 0,
-         totalBytes: 0,
-         fileRoleRequirements: [],
-         operationType: "UNKNOWN",
-         messages: []
-       };
-     }
- 
-     let activeTurn = createEmptyTurnState();
- 
-     const conversationTurns = [];
- 
-     let currentStrategyCandidates = [];
-     let currentRequestText = "";
- 
-     function snapshotTurn(turn) {
-       return {
-         request: turn.request,
-         projectId: turn.projectId,
-         proposalId: turn.proposalId,
-         draft: turn.draft ? JSON.parse(JSON.stringify(turn.draft)) : null,
-         preview: Array.isArray(turn.preview) ? JSON.parse(JSON.stringify(turn.preview)) : [],
-         requiredRoles: Array.isArray(turn.requiredRoles) ? [...turn.requiredRoles] : [],
-         approvalPolicyVersion: turn.approvalPolicyVersion,
-         operationMode: turn.operationMode,
-         fileCount: turn.fileCount,
-         totalBytes: turn.totalBytes,
-         fileRoleRequirements: Array.isArray(turn.fileRoleRequirements)
-           ? JSON.parse(JSON.stringify(turn.fileRoleRequirements))
-           : [],
-         operationType: turn.operationType,
-         messages: Array.isArray(turn.messages)
-           ? JSON.parse(JSON.stringify(turn.messages))
-           : []
-       };
-     }
- 
-     function finalizeActiveTurn(extra = {}) {
-       if (!activeTurn.request) {
-         return;
-       }
- 
-       conversationTurns.push({
-         ...snapshotTurn(activeTurn),
-         ...extra
-       });
- 
-       renderConversationTurns(conversationTurns);
-     }
- 
-     function renderConversationTurns(items) {
-       conversationHistoryBox.innerHTML = "";
- 
-       if (!Array.isArray(items) || items.length === 0) {
-         const empty = document.createElement("div");
-         empty.className = "file-card empty";
-         empty.textContent = "No conversation turns yet.";
-         conversationHistoryBox.appendChild(empty);
-         return;
-       }
- 
-       [...items].reverse().forEach((item, index) => {
-         const card = document.createElement("div");
-         card.className = "file-card";
- 
-         const titleEl = document.createElement("div");
-         titleEl.className = "file-path";
-         titleEl.textContent = `Turn ${items.length - index}`;
- 
-         const summaryEl = document.createElement("div");
-         summaryEl.className = "file-preview";
-         summaryEl.textContent =
-           `Request: ${item.request || ""}\n` +
-           `Proposal ID: ${item.proposalId || "n/a"}\n` +
-           `Operation Type: ${item.operationType || "UNKNOWN"}\n` +
-           `Final Status: ${item.finalStatus || "IN_PROGRESS"}\n` +
-           `Decision Packet ID: ${item.decisionPacketId || "n/a"}\n` +
-           `File Count: ${item.fileCount || 0}`;
- 
-         card.appendChild(titleEl);
-         card.appendChild(summaryEl);
-         conversationHistoryBox.appendChild(card);
-       });
-     }
- 
-     function setStatus(text) {
-       statusBox.textContent = text;
-     }
- 
-     function renderResponse(data) {
-       if (!data) {
-         responseBox.textContent = "No response yet.";
-         responseBox.classList.add("empty");
-         return;
-       }
- 
-       responseBox.textContent = JSON.stringify(data, null, 2);
-       responseBox.classList.remove("empty");
-     }
- 
-     function renderFiles(files) {
-       filesBox.innerHTML = "";
- 
-       if (!Array.isArray(files) || files.length === 0) {
-         const empty = document.createElement("div");
-         empty.className = "file-card empty";
-         empty.textContent = "No files proposed yet.";
-         filesBox.appendChild(empty);
-         return;
-       }
- 
-       files.forEach((file) => {
-         const card = document.createElement("div");
-         card.className = "file-card";
- 
-         const pathEl = document.createElement("div");
-         pathEl.className = "file-path";
-         pathEl.textContent = file.path || "Unknown path";
- 
-         const previewEl = document.createElement("div");
-         previewEl.className = "file-preview";
-         previewEl.textContent = file.content || "";
- 
-         card.appendChild(pathEl);
-         card.appendChild(previewEl);
-         filesBox.appendChild(card);
-       });
-     }
- 
-         function renderApprovalInfo(requiredRoles, policyVersion) {
-       const roles = Array.isArray(requiredRoles) ? requiredRoles : [];
-       const selectedRole = String(approverRoleSelect.value || "").trim();
- 
-       approvalInfoBox.textContent =
-         `Policy version: ${policyVersion || "unknown"}\n` +
-         `Required roles: ${roles.join(", ") || "none"}\n` +
-         `Selected role: ${selectedRole || "none"}`;
- 
-       approvalInfoBox.classList.remove("empty");
-     }
- 
-     function renderOperationInfo(operationMode, fileCount, totalBytes, fileRoleRequirements) {
-       const rows = Array.isArray(fileRoleRequirements) ? fileRoleRequirements : [];
- 
-       const lines = [
-         `Operation mode: ${operationMode || "unknown"}`,
-         `File count: ${fileCount || 0}`,
-         `Total bytes: ${totalBytes || 0}`
-       ];
- 
-       if (rows.length > 0) {
-         lines.push("");
-         lines.push("Per-file roles:");
-         rows.forEach((row) => {
-           lines.push(`- ${row.path}: ${(row.required_roles || []).join(", ") || "none"}`);
-         });
-       }
- 
-       operationInfoBox.textContent = lines.join("\n");
-       operationInfoBox.classList.remove("empty");
-     }
- 
-     function populateApproverRoles(roles) {
-       const normalized = Array.isArray(roles) && roles.length > 0 ? roles : ["cto"];
-       const previousValue = approverRoleSelect.value;
- 
-       approverRoleSelect.innerHTML = "";
- 
-       normalized.forEach((role) => {
-         const option = document.createElement("option");
-         option.value = role;
-         option.textContent = role;
-         approverRoleSelect.appendChild(option);
-       });
- 
-       if (normalized.includes(previousValue)) {
-         approverRoleSelect.value = previousValue;
-       }
-     }
- 
-     function renderHistory(items) {
-       historyBox.innerHTML = "";
- 
-       if (!Array.isArray(items) || items.length === 0) {
-         const empty = document.createElement("div");
-         empty.className = "file-card empty";
-         empty.textContent = "No write history yet.";
-         historyBox.appendChild(empty);
-         return;
-       }
- 
-       items.forEach((item) => {
-         const card = document.createElement("div");
-         card.className = "file-card";
- 
-         const idEl = document.createElement("div");
-         idEl.className = "file-path";
-         idEl.textContent = item.decision_packet_id || item.write_id || "Unknown activity id";
- 
-         const files = Array.isArray(item.queued_files) && item.queued_files.length > 0
-         ? item.queued_files
-         : (Array.isArray(item.written_files) ? item.written_files : []);
- 
-         const summaryEl = document.createElement("div");
-         summaryEl.className = "file-preview";
-         summaryEl.textContent =
-         `Type: ${item.entry_type || "UNKNOWN"}\n` +
